91	/// Load profile names from the XDG config profiles directory.
92	///
93	/// Returns the directory names of all subdirectories that contain a `pack.yaml`
94	/// file, matching the format expected by `Pack::load_from_dir` and
95	/// `handle_switch_profile`. Flat `.yaml` files at the profiles root are ignored.
96	pub fn load_profiles() -> Vec<String> {
97	    let profiles_dir = BaseDirectories::with_prefix("vibe-attack")
98	        .get_config_home()
99	        .map(|p| p.join("profiles"));
100	
101	    let Some(dir) = profiles_dir else {
102	        info!(count = 0, "Profiles dir not resolvable; no profiles loaded");
103	        return Vec::new();
104	    };
105	
106	    if !dir.is_dir() {
107	        info!(path = %dir.display(), count = 0, "Profiles dir not found");
108	        return Vec::new();
109	    }
110	
111	    let mut names: Vec<String> = std::fs::read_dir(&dir)
112	        .into_iter()
113	        .flatten()
114	        .flatten()
115	        .filter_map(|entry| {
116	            let path = entry.path();
117	            if entry.file_type().ok()?.is_dir() && path.join("pack.yaml").exists() {
118	                path.file_name()
119	                    .and_then(|s| s.to_str())
120	                    .map(|s| s.to_string())
121	            } else {
122	                None
123	            }
124	        })
125	        .collect();
126	
127	    names.sort();
128	    info!(path = %dir.display(), count = names.len(), "Profiles loaded");
129	    names
130	}
